import { MdOutlineTheaters } from "react-icons/md";
import { useLanguage } from "../../context/language";
import { Languages } from "../utils/dmdb.props";
import { Switch } from "@mui/material";
import ToggleSwitch from "../switch/toggle-switch";

export function Headers() {
  const { language, setLanguage } = useLanguage();
  const buttonInactiveClass: string = "opacity-25 transition-all";

  function handleLanguageChange(languageOption: Languages) {
    setLanguage(languageOption);

    localStorage.setItem("dmdb-language", languageOption);
  }

  function getFlagButtonClass(buttonLanguage: Languages) {
    if (language !== buttonLanguage) {
      return buttonInactiveClass;
    }

    return "";
  }

  return (
    <div className="bg-slate-800 flex justify-between h-24 w-100">
      <div className="flex text-6xl text-white font-montserrat pl-9 pt-4">
        DMDB
        <MdOutlineTheaters />
      </div>
      <div>
        <ToggleSwitch />
      </div>
      <div className="flex items-center text-2xl mr-5">
        <button
          className={getFlagButtonClass("enus")}
          onClick={() => handleLanguageChange("enus")}
        >
          🇺🇸
        </button>
        <button
          className={getFlagButtonClass("ptbr")}
          onClick={() => handleLanguageChange("ptbr")}
        >
          🇧🇷
        </button>
      </div>
    </div>
  );
}
